package main

import (
    "bufio"
    "fmt"
    "os"
    "strconv"
    "strings"
)

func abs(x int) int {
    if x < 0 {
        return -x
    }
    return x
}

func canPlace(line []rune, pos int, digit rune, lim int) bool {
    for i, ch := range line {
        if ch == digit && abs(i-pos) <= lim {
            return false
        }
    }
    return true
}

func fill(line []rune, lim int) bool {
    for i, ch := range line {
        if ch != '.' {
            continue
        }
        for d := 0; d <= lim; d++ {
            digit := rune('0' + d)
            if canPlace(line, i, digit, lim) {
                line[i] = digit
                if fill(line, lim) {
                    return true
                }
                line[i] = '.'
            }
        }
        return false
    }
    return true
}

func main() {
    scanner := bufio.NewScanner(os.Stdin)
    if !scanner.Scan() {
        return
    }
    line := scanner.Text()
    if !scanner.Scan() {
        return
    }
    lim, err := strconv.Atoi(strings.TrimSpace(scanner.Text()))
    if err != nil {
        return
    }

    lineRunes := []rune(line)
    if fill(lineRunes, lim) {
        fmt.Println(string(lineRunes))
    }
}
